/** @public */
export interface CollapsiblePanel {
    /** Controls whether the panel is collapsed */
    collapsed?: boolean;
    /** Default value for the collapsed state */
    defaultCollapsed?: boolean;
    /** Fired when the value of collapsed changes or should change */
    onCollapsedChange?: (value: boolean) => void;
    /** The `min-width` for the container at which the collapse should fire automatically */
    breakpoint?: number;
}
